public void testNumberAsStringDeserializationWithDecimal() {
  Number value = gson.fromJson("\"3.14\"", Number.class);
  assertEquals(3.14, value.doubleValue(), 0.001);
}

public void testNumberAsStringDeserializationWithNegative() {
  Number value = gson.fromJson("\"-42\"", Number.class);
  assertEquals(-42, value.intValue());
}

public void testNumberAsStringDeserializationWithScientificNotation() {
  Number value = gson.fromJson("\"1.5e10\"", Number.class);
  assertEquals(1.5e10, value.doubleValue(), 0.001);
}
